//! Conformance tests — `ferrotorch_ml::datasets` module.
//!
//! Tracking issue: <https://github.com/dollspace-gay/ferrotorch/issues/840>.
//!
//! Reference library: scikit-learn 1.5.2 (pinned).
//! Fixtures generated by `scripts/regenerate_ml_fixtures.py`.
//!
//! Dataset functions return `(X, y)` tensor pairs. The conformance claims are:
//!
//! 1. Shape — `X.shape() == expected_x_shape`, `y.shape() == expected_y_shape`.
//! 2. Label range — class labels lie in `[label_min, label_max]` (inclusive).
//! 3. Integer-encoded labels — `y` values have zero fractional part.
//! 4. Determinism — same `random_state` yields the same shapes on every run
//!    (ferrolearn_datasets is deterministic given a fixed seed).
//! 5. Finiteness — every feature value in `X` is finite.
//!
//! We do NOT compare raw feature values against sklearn's `X` output because
//! ferrolearn_datasets is an independent Rust implementation — it produces the
//! same *contract* (shapes, dtypes, label ranges) but not necessarily the same
//! pseudo-random sequence as sklearn's Python generator.

use std::path::PathBuf;

use ferrotorch_ml::datasets::{
    load_breast_cancer, load_iris, load_wine, make_blobs, make_circles, make_classification,
    make_moons, make_regression,
};
use serde::Deserialize;

// ---------------------------------------------------------------------------
// Fixture loading
// ---------------------------------------------------------------------------

#[derive(Debug, Deserialize, Clone)]
struct FixtureFile {
    #[allow(dead_code, reason = "metadata kept for diagnostics")]
    metadata: serde_json::Value,
    fixtures: Vec<Fixture>,
}

#[derive(Debug, Deserialize, Clone)]
struct Fixture {
    op: String,
    #[serde(default)]
    expected_x_shape: Option<Vec<usize>>,
    #[serde(default)]
    expected_y_shape: Option<Vec<usize>>,
    #[serde(default)]
    label_min: Option<i64>,
    #[serde(default)]
    label_max: Option<i64>,
    #[serde(default)]
    n_samples: Option<usize>,
    #[serde(default)]
    n_features: Option<usize>,
    #[serde(default)]
    n_classes: Option<usize>,
    #[serde(default)]
    random_state: Option<u64>,
    #[serde(default)]
    n_informative: Option<usize>,
    #[serde(default)]
    noise: Option<f64>,
    #[serde(default)]
    centers: Option<usize>,
    #[serde(default)]
    cluster_std: Option<f64>,
    #[serde(default)]
    factor: Option<f64>,
    #[serde(flatten)]
    _rest: serde_json::Value,
}

fn load_fixtures() -> FixtureFile {
    let p = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
        .join("tests")
        .join("conformance")
        .join("fixtures.json");
    let bytes = std::fs::read(&p).unwrap_or_else(|e| {
        panic!(
            "read {} failed: {e}. Run python3 scripts/regenerate_ml_fixtures.py first.",
            p.display()
        )
    });
    serde_json::from_slice(&bytes).unwrap_or_else(|e| panic!("parse {}: {e}", p.display()))
}

fn find(file: &FixtureFile, op: &str) -> Fixture {
    file.fixtures
        .iter()
        .find(|f| f.op == op)
        .unwrap_or_else(|| panic!("no fixture with op={op:?}"))
        .clone()
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

fn check_label_range(y_data: &[f64], label_min: i64, label_max: i64, label: &str) {
    for &v in y_data {
        assert!(
            v.fract() == 0.0,
            "{label}: label {v} is not integer-valued"
        );
        let vi = v as i64;
        assert!(
            vi >= label_min && vi <= label_max,
            "{label}: label {vi} not in [{label_min}, {label_max}]"
        );
    }
}

fn check_x_finite(x_data: &[f64], label: &str) {
    for &v in x_data {
        assert!(v.is_finite(), "{label}: feature value {v} is not finite");
    }
}

// ============================================================================
// make_classification
// ============================================================================

#[test]
fn make_classification_shape_and_labels() {
    let file = load_fixtures();
    let f = find(&file, "dataset_make_classification");
    let n_samples = f.n_samples.expect("n_samples");
    let n_features = f.n_features.expect("n_features");
    let n_classes = f.n_classes.expect("n_classes");
    let random_state = f.random_state;
    let expected_x = f.expected_x_shape.as_ref().expect("expected_x_shape");
    let expected_y = f.expected_y_shape.as_ref().expect("expected_y_shape");
    let label_min = f.label_min.expect("label_min");
    let label_max = f.label_max.expect("label_max");

    let (x, y) = make_classification::<f64>(n_samples, n_features, n_classes, random_state)
        .expect("make_classification");

    assert_eq!(x.shape(), expected_x.as_slice(), "make_classification X shape");
    assert_eq!(y.shape(), expected_y.as_slice(), "make_classification y shape");

    let y_data = y.data().expect("y data");
    check_label_range(y_data, label_min, label_max, "make_classification");
    check_x_finite(x.data().expect("x data"), "make_classification");
}

