#[test]
fn make_regression_shape_and_finiteness() {
    let file = load_fixtures();
    let f = find(&file, "dataset_make_regression");
    let n_samples = f.n_samples.expect("n_samples");
    let n_features = f.n_features.expect("n_features");
    let n_informative = f.n_informative.expect("n_informative");
    let noise = f.noise.expect("noise");
    let random_state = f.random_state;
    let expected_x = f.expected_x_shape.as_ref().expect("expected_x_shape");
    let expected_y = f.expected_y_shape.as_ref().expect("expected_y_shape");

    let (x, y) = make_regression::<f64>(n_samples, n_features, n_informative, noise, random_state)
        .expect("make_regression");

    assert_eq!(x.shape(), expected_x.as_slice(), "make_regression X shape");
    assert_eq!(y.shape(), expected_y.as_slice(), "make_regression y shape");

    check_x_finite(x.data().expect("x data"), "make_regression X");
    for &v in y.data().expect("y data") {
        assert!(v.is_finite(), "make_regression y: {v} not finite");
    }
}

