// ============================================================================
// make_moons
// ============================================================================

#[test]
fn make_moons_binary_labels_and_shape() {
    let file = load_fixtures();
    let f = find(&file, "dataset_make_moons");
    let n_samples = f.n_samples.expect("n_samples");
    let noise = f.noise.expect("noise");
    let random_state = f.random_state;
    let expected_x = f.expected_x_shape.as_ref().expect("expected_x_shape");
    let expected_y = f.expected_y_shape.as_ref().expect("expected_y_shape");
    let label_min = f.label_min.expect("label_min");
    let label_max = f.label_max.expect("label_max");

    let (x, y) = make_moons::<f64>(n_samples, noise, random_state).expect("make_moons");

    assert_eq!(x.shape(), expected_x.as_slice(), "make_moons X shape");
    assert_eq!(y.shape(), expected_y.as_slice(), "make_moons y shape");
    // Binary: labels must be exactly 0 or 1.
    check_label_range(y.data().expect("y"), label_min, label_max, "make_moons");
    for &v in y.data().expect("y") {
        assert!(v == 0.0 || v == 1.0, "make_moons: label {v} not binary");
    }
    check_x_finite(x.data().expect("x"), "make_moons");
}

