// ============================================================================
// Fixture sanity
// ============================================================================

#[test]
fn fixture_file_covers_every_dataset_op() {
    let file = load_fixtures();
    let ops: Vec<&str> = file.fixtures.iter().map(|f| f.op.as_str()).collect();

    let required = [
        "dataset_make_classification",
        "dataset_make_regression",
        "dataset_make_blobs",
        "dataset_make_moons",
        "dataset_make_circles",
        "dataset_load_iris",
        "dataset_load_wine",
        "dataset_load_breast_cancer",
    ];

    for r in &required {
        assert!(ops.contains(r), "fixture file missing required op {r:?}");
    }
}
